dslRule:
/*!id: jdt.internal.astmatcher.singlevariabledeclaration.varargs-annotations*/
/*!description: Updates internal JDT ASTMatcher to compare varargs annotations for SingleVariableDeclaration nodes, supporting Java 8+ varargs annotation feature.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, java8*/
node.getExtraDimensions() == o.getExtraDimensions()
				&& safeSubtreeMatch(node.getInitializer(), o.getInitializer())
:: inClass("org.eclipse.jdt.core.dom.ASTMatcher") && inMethod("match")
=> node.getExtraDimensions() == o.getExtraDimensions()
				&& safeSubtreeMatch(node.getInitializer(), o.getInitializer())
				&& (this.level >= org.eclipse.jdt.core.dom.AST.JLS8 && node.isVarargs()) ? safeSubtreeListMatch(node.varargsAnnotations(), o.varargsAnnotations()) : true
;;

dslRuleAfterChange:
/*!id: jdt.internal.astconverter.foreach.sourcespan.fix*/
/*!description: Corrects the source span calculation for for-each loop iteration variables in ASTConverter to prevent overlap with the collection expression.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, bugfix, refactoring*/
Math.max($typeEnd, $localDeclaration.declarationSourceEnd)
=> Math.max($typeEnd, (($localDeclaration.bits & org.eclipse.jdt.internal.compiler.ast.ASTNode.IsForeachElementVariable) != 0) ? $localDeclaration.sourceEnd : $localDeclaration.declarationSourceEnd)
;;

/* Example of what a hypothetical DSL extension could look like for insertion */
@id: jdt.internal.naiveastflattener.extradimension.annotations.space
@severity: info
@target: org.eclipse.jdt.core.dom.NaiveASTFlattener.visit(org.eclipse.jdt.core.dom.ExtraDimension)
insert before: visitAnnotationsList(node.annotations())
=> this.buffer.append(" ");
;;

dslRule:
/*!id: jdt.internal.importrewriteanalyzer.addimport.arg-addition*/
/*!description: Updates an internal ImportRewriteAnalyzer.addImport call to include new AST root and restore flags arguments for improved comment preservation logic. This rule targets the call site within ImportRewrite.java.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
$analyzer.addImport($name.substring(1), $isStatic) :: inClass("org.eclipse.jdt.core.dom.rewrite.ImportRewrite") && inMethod("doTextEdit")
=> $analyzer.addImport($name.substring(1), $isStatic, this.fUsedAstRoot, this.restoreExistingImports)
;;

/*!id: jdt.internal.methoddecl.thrownexceptions.property.ischanged*/
/*!description: Updates internal JDT ASTRewriteAnalyzer's usage of MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY to conditionally use THROWN_EXCEPTION_TYPES_PROPERTY for JLS8+ API levels, improving AST consistency for method throws clauses.*/
/*!severity: info*/
isChanged($node, org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY)
=> isChanged($node, $node.getAST().apiLevel() < org.eclipse.jdt.core.dom.AST.JLS8 ? org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY : org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTION_TYPES_PROPERTY)
;;

/*!id: jdt.internal.methoddecl.thrownexceptions.property.rewritenodelist*/
/*!description: Updates internal JDT ASTRewriteAnalyzer's usage in rewriteNodeList to conditionally use MethodDeclaration.THROWN_EXCEPTION_TYPES_PROPERTY for JLS8+ API levels, ensuring correct rewriting of method throws clauses.*/
/*!severity: info*/
rewriteNodeList($node, org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY, $pos, " throws ", ", ")
=> rewriteNodeList($node, $node.getAST().apiLevel() < org.eclipse.jdt.core.dom.AST.JLS8 ? org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY : org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTION_TYPES_PROPERTY, $pos, " throws ", ", ")
;;

/*!id: jdt.internal.methoddecl.thrownexceptions.property.visitlist*/
/*!description: Updates internal JDT ASTRewriteFlattener's usage in visitList to conditionally use MethodDeclaration.THROWN_EXCEPTION_TYPES_PROPERTY for JLS8+ API levels, ensuring correct flattening of method throws clauses.*/
/*!severity: info*/
visitList($node, org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY, java.lang.String.valueOf(','), " throws ", org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING)
=> visitList($node, $node.getAST().apiLevel() < org.eclipse.jdt.core.dom.AST.JLS8 ? org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTIONS_PROPERTY : org.eclipse.jdt.core.dom.MethodDeclaration.THROWN_EXCEPTION_TYPES_PROPERTY, java.lang.String.valueOf(','), " throws ", org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING)
;;
